// BankingServiceImpl.java
package com.bank.service;

import com.bank.model.BankingTransaction;
import com.bank.model.TransactionRequest;
import com.bank.model.TransactionResponse;
import javax.jws.WebService;
import javax.xml.ws.WebServiceContext;
import javax.annotation.Resource;
import java.math.BigDecimal;
import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.Map;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;
import java.util.logging.Logger;

@WebService(
    serviceName = "BankingService",
    portName = "BankingServicePort",
    targetNamespace = "http://service.bank.com/",
    endpointInterface = "com.bank.service.BankingService"
)
public class BankingServiceImpl implements BankingService {
    
    private static final Logger LOGGER = Logger.getLogger(BankingServiceImpl.class.getName());
    private static final Map<String, BankingTransaction> transactions = new ConcurrentHashMap<>();
    
    @Resource
    private WebServiceContext wsContext;
    
    @Override
    public TransactionResponse processTransaction(TransactionRequest request) {
        LOGGER.info("Processing transaction from " + request.getFromAccount() + 
                   " to " + request.getToAccount());
        
        try {
            validateTransaction(request);
            
            String transactionId = UUID.randomUUID().toString();
            BankingTransaction transaction = new BankingTransaction(
                transactionId,
                request.getFromAccount(),
                request.getToAccount(),
                request.getAmount(),
                request.getCurrency(),
                request.getDescription()
            );
            
            boolean success = executeTransaction(transaction);
            
            if (success) {
                transaction.setStatus("COMPLETED");
                transactions.put(transactionId, transaction);
                
                return new TransactionResponse(
                    transactionId,
                    "SUCCESS",
                    "Transaction completed successfully",
                    formatTimestamp(transaction.getTimestamp())
                );
            } else {
                transaction.setStatus("FAILED");
                transactions.put(transactionId, transaction);
                
                return new TransactionResponse(
                    transactionId,
                    "FAILED",
                    "Transaction failed due to insufficient funds",
                    formatTimestamp(transaction.getTimestamp())
                );
            }
            
        } catch (Exception e) {
            LOGGER.severe("Transaction processing failed: " + e.getMessage());
            return new TransactionResponse(
                null,
                "ERROR",
                "Transaction processing error: " + e.getMessage(),
                formatTimestamp(new Date())
            );
        }
    }
    
    @Override
    public TransactionResponse getTransactionStatus(String transactionId) {
        LOGGER.info("Getting status for transaction: " + transactionId);
        
        BankingTransaction transaction = transactions.get(transactionId);
        
        if (transaction != null) {
            return new TransactionResponse(
                transaction.getTransactionId(),
                transaction.getStatus(),
                "Transaction found",
                formatTimestamp(transaction.getTimestamp())
            );
        } else {
            return new TransactionResponse(
                transactionId,
                "NOT_FOUND",
                "Transaction not found",
                formatTimestamp(new Date())
            );
        }
    }
    
    @Override
    public TransactionResponse cancelTransaction(String transactionId) {
        LOGGER.info("Canceling transaction: " + transactionId);
        
        BankingTransaction transaction = transactions.get(transactionId);
        
        if (transaction != null) {
            if ("COMPLETED".equals(transaction.getStatus())) {
                return new TransactionResponse(
                    transactionId,
                    "ERROR",
                    "Cannot cancel completed transaction",
                    formatTimestamp(new Date())
                );
            }
            
            transaction.setStatus("CANCELLED");
            return new TransactionResponse(
                transactionId,
                "SUCCESS",
                "Transaction cancelled successfully",
                formatTimestamp(new Date())
            );
        } else {
            return new TransactionResponse(
                transactionId,
                "NOT_FOUND",
                "Transaction not found",
                formatTimestamp(new Date())
            );
        }
    }
    
    private void validateTransaction(TransactionRequest request) throws Exception {
        if (request.getFromAccount() == null || request.getFromAccount().isEmpty()) {
            throw new Exception("From account is required");
        }
        if (request.getToAccount() == null || request.getToAccount().isEmpty()) {
            throw new Exception("To account is required");
        }
        if (request.getAmount() == null || request.getAmount().compareTo(BigDecimal.ZERO) <= 0) {
            throw new Exception("Amount must be greater than zero");
        }
        if (request.getCurrency() == null || request.getCurrency().isEmpty()) {
            throw new Exception("Currency is required");
        }
    }
    
    private boolean executeTransaction(BankingTransaction transaction) {
        return transaction.getAmount().compareTo(new BigDecimal("10000")) <= 0;
    }
    
    private String formatTimestamp(Date date) {
        SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSSZ");
        return sdf.format(date);
    }
}

